targets.expr:
100 *
sum by (ecs_task, version) (
  jvm_memory_used_bytes{area="heap", service_name=~"$service_name", env=~"$env"}
)
/
sum by (ecs_task, version) (
  jvm_memory_max_bytes{area="heap", service_name=~"$service_name", env=~"$env"}
)

sum by (ecs_task, version) (
  jvm_memory_max_bytes{
    service_name=~"$service_name",
    env=~"$env",
    area="heap"
  }
) / 1000000

sum by (ecs_task, version) (
  jvm_memory_used_bytes{
    service_name=~"$service_name",
    env=~"$env",
    area="heap"
  }
) / 1000000

sum by (ecs_task, version) (
  jvm_memory_used_bytes{
    service_name=~"$service_name",
    env=~"$env",
    area="nonheap"
  }
) / 1000000

100 *
sum by (ecs_task, version) (
  rate(jvm_gc_pause_seconds_sum{
    service_name=~"$service_name",
    env=~"$env"
  }[5m])
)

60 *
sum by (ecs_task, version) (
  rate(jvm_gc_pause_seconds_count{
    service_name=~"$service_name",
    env=~"$env"
  }[5m])
)
